        for ( size_t i = 0; i < dict->mod; i++ )
        {
            for ( dict_elem_t* curr = dict->list[i].head; curr != NULL; curr = curr->next )
            {
                strlen_table[index] = (uint32_t) strlen( *(char**) curr->key );
                *bytes += strlen_table[index];
                index++;
            }
        }
    }

    void* data = dict->alloc.malloc( *bytes );
