    memcpy( ptr, key_val_size, sizeof (uint32_t) * 3 );
    ptr += sizeof (uint32_t) * 3;

    if ( dict->key.type == DICT_STR )
    {
        size_t index = 0;
        char* str_ptr = ptr + size * elem_size;
