                ptr += dict->val.size;
                memcpy( str_ptr, *(char**) curr->key, strlen_table[index] );
                str_ptr += strlen_table[index];
                index++;
            }
        }
    }
    else
    {
        for ( size_t i = 0; i < dict->mod; i++ )
        {
            for ( dict_elem_t* curr = dict->list[i].head; curr != NULL; curr = curr->next )
            {
